### 第 20 题（2025 真题）完善程序：字符串解码。①处应填？

```cpp
#include<cctype>
#include<iostream>
#include<string>
using namespace std;
int main(){
    string z;
    cin>> z;
    string s="";
    for(int i=0;;){
        char ch= z[i];
        if( ①  &&isdigit(z[i+1])){
            int count=0;
            i++;
            while(i<z.length()&& isdigit(z[i])){
                count= count*10+(z[i]-'0');
                i++;
            }
            for(int j=0; j< count ;++j){
                s+= ch;
            }
        }else{
              s+= ch;
            i++;
        }
    }
    cout<< s<< endl;
    return 0;
}
```

